import{_ as t,c as n,o as i,a1 as a}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Bear-Integration: Pläne automatisch speichern | Plannotator","description":"Erfahren Sie, wie Sie die Bear-Integration in Plannotator konfigurieren. Speichern Sie genehmigte Pläne automatisch über x-callback-url, generieren Sie intelligente Tags und archivieren Sie Ihr Wissen.","frontmatter":{"title":"Bear-Integration: Pläne automatisch speichern | Plannotator","sidebarTitle":"Pläne automatisch in Bear speichern","subtitle":"Bear-Integration: Genehmigte Pläne automatisch speichern | Plannotator","description":"Erfahren Sie, wie Sie die Bear-Integration in Plannotator konfigurieren. Speichern Sie genehmigte Pläne automatisch über x-callback-url, generieren Sie intelligente Tags und archivieren Sie Ihr Wissen.","tags":["Integration","Bear","Notiz-App","Wissensmanagement"],"prerequisite":["installation-claude-code","platforms-plan-review-basics"],"order":3},"headers":[],"relativePath":"de/backnotprop/plannotator/advanced/bear-integration/index.md","filePath":"de/backnotprop/plannotator/advanced/bear-integration/index.md"}'),r={name:"de/backnotprop/plannotator/advanced/bear-integration/index.md"};function l(o,e,s,d,c,h){return i(),n("div",null,[...e[0]||(e[0]=[a(`<h1 id="bear-integration-genehmigte-plane-automatisch-speichern" tabindex="-1">Bear-Integration: Genehmigte Pläne automatisch speichern <a class="header-anchor" href="#bear-integration-genehmigte-plane-automatisch-speichern" aria-label="Permalink to &quot;Bear-Integration: Genehmigte Pläne automatisch speichern&quot;">​</a></h1><h2 id="was-sie-lernen-werden" tabindex="-1">Was Sie lernen werden <a class="header-anchor" href="#was-sie-lernen-werden" aria-label="Permalink to &quot;Was Sie lernen werden&quot;">​</a></h2><p>Nach der Aktivierung der Bear-Integration speichert Plannotator bei jeder Plangenehmigung automatisch den Plan in Ihren Bear-Notizen, einschließlich:</p><ul><li>Automatisch generierter Titel (aus dem Plan extrahiert)</li><li>Intelligente Tags (Projektname, Schlüsselwörter, Programmiersprachen)</li><li>Vollständiger Planinhalt</li></ul><p>So können Sie alle genehmigten Pläne an einem Ort verwalten, um sie später nachzuschlagen und Wissen zu sammeln.</p><h2 id="das-problem" tabindex="-1">Das Problem <a class="header-anchor" href="#das-problem" aria-label="Permalink to &quot;Das Problem&quot;">​</a></h2><p>Vielleicht kennen Sie diese Situationen:</p><ul><li>Der KI-generierte Plan ist gut, aber Sie möchten ihn für später speichern</li><li>Manuelles Kopieren und Einfügen von Plänen in Bear ist umständlich</li><li>Pläne verschiedener Projekte sind durcheinander, ohne Tag-Verwaltung</li></ul><p>Mit der Bear-Integration werden all diese Probleme automatisch gelöst.</p><h2 id="wann-sie-diese-funktion-nutzen-sollten" tabindex="-1">Wann Sie diese Funktion nutzen sollten <a class="header-anchor" href="#wann-sie-diese-funktion-nutzen-sollten" aria-label="Permalink to &quot;Wann Sie diese Funktion nutzen sollten&quot;">​</a></h2><ul><li>Sie verwenden Bear als Ihre Haupt-Notiz-App</li><li>Sie müssen genehmigte Pläne als Wissensdatenbank archivieren</li><li>Sie möchten historische Pläne schnell über Tags finden</li></ul><div class="info custom-block"><p class="custom-block-title">Über Bear</p><p>Bear ist eine Markdown-Notiz-App für macOS mit Unterstützung für Tags, Verschlüsselung, Synchronisierung und mehr. Falls Sie Bear noch nicht installiert haben, besuchen Sie <a href="https://bear.app/" target="_blank" rel="noreferrer">bear.app</a> für weitere Informationen.</p></div><h2 id="🎒-voraussetzungen" tabindex="-1">🎒 Voraussetzungen <a class="header-anchor" href="#🎒-voraussetzungen" aria-label="Permalink to &quot;🎒 Voraussetzungen&quot;">​</a></h2><ul><li>Plannotator ist installiert (siehe <a href="./../../start/installation-claude-code/">Installationsanleitung</a>)</li><li>Bear ist installiert und funktioniert ordnungsgemäß</li><li>Sie kennen den grundlegenden Plan-Review-Prozess (siehe <a href="./../../platforms/plan-review-basics/">Plan-Review-Grundlagen</a>)</li></ul><h2 id="kernkonzept" tabindex="-1">Kernkonzept <a class="header-anchor" href="#kernkonzept" aria-label="Permalink to &quot;Kernkonzept&quot;">​</a></h2><p>Der Kern der Bear-Integration ist das <strong>x-callback-url</strong>-Protokoll:</p><ol><li>Aktivieren Sie die Bear-Integration in der Plannotator-UI (gespeichert im Browser-localStorage)</li><li>Bei der Plangenehmigung sendet Plannotator eine <code>bear://x-callback-url/create</code>-URL</li><li>Das System öffnet Bear automatisch mit dem <code>open</code>-Befehl, um eine Notiz zu erstellen</li><li>Planinhalt, Titel und Tags werden automatisch ausgefüllt</li></ol><p><strong>Hauptmerkmale</strong>:</p><ul><li>Keine Vault-Pfad-Konfiguration erforderlich (anders als bei Obsidian)</li><li>Intelligente Tag-Generierung (maximal 7)</li><li>Automatisches Speichern bei Plangenehmigung</li></ul><div class="tip custom-block"><p class="custom-block-title">Unterschied zu Obsidian</p><p>Die Bear-Integration ist einfacher und erfordert keine Vault-Pfad-Konfiguration – nur einen Schalter. Obsidian hingegen ermöglicht die Angabe von Speicherordnern und mehr Anpassungsmöglichkeiten.</p></div><h2 id="schritt-fur-schritt-anleitung" tabindex="-1">Schritt-für-Schritt-Anleitung <a class="header-anchor" href="#schritt-fur-schritt-anleitung" aria-label="Permalink to &quot;Schritt-für-Schritt-Anleitung&quot;">​</a></h2><h3 id="schritt-1-plannotator-einstellungen-offnen" tabindex="-1">Schritt 1: Plannotator-Einstellungen öffnen <a class="header-anchor" href="#schritt-1-plannotator-einstellungen-offnen" aria-label="Permalink to &quot;Schritt 1: Plannotator-Einstellungen öffnen&quot;">​</a></h3><p>Nachdem der KI-Agent einen Plan generiert und die Plannotator-UI geöffnet hat, klicken Sie auf die ⚙️ <strong>Settings</strong>-Schaltfläche oben rechts.</p><p><strong>Erwartetes Ergebnis</strong>: Das Einstellungsfenster öffnet sich mit mehreren Konfigurationsoptionen</p><h3 id="schritt-2-bear-integration-aktivieren" tabindex="-1">Schritt 2: Bear-Integration aktivieren <a class="header-anchor" href="#schritt-2-bear-integration-aktivieren" aria-label="Permalink to &quot;Schritt 2: Bear-Integration aktivieren&quot;">​</a></h3><p>Suchen Sie im Einstellungsfenster den Abschnitt <strong>Bear Notes</strong> und klicken Sie auf den Schalter.</p><p><strong>Warum</strong> Der Schalter wechselt von grau (deaktiviert) zu blau (aktiviert) und wird gleichzeitig im localStorage des Browsers gespeichert.</p><p><strong>Erwartetes Ergebnis</strong>:</p><ul><li>Der Bear Notes-Schalter wird blau</li><li>Beschreibungstext: „Auto-save approved plans to Bear&quot;</li></ul><h3 id="schritt-3-plan-genehmigen" tabindex="-1">Schritt 3: Plan genehmigen <a class="header-anchor" href="#schritt-3-plan-genehmigen" aria-label="Permalink to &quot;Schritt 3: Plan genehmigen&quot;">​</a></h3><p>Klicken Sie nach Abschluss der Plan-Review auf die <strong>Approve</strong>-Schaltfläche unten.</p><p><strong>Warum</strong> Plannotator liest die Bear-Einstellungen und ruft bei aktivierter Integration die x-callback-url von Bear auf.</p><p><strong>Erwartetes Ergebnis</strong>:</p><ul><li>Die Bear-App öffnet sich automatisch</li><li>Ein neues Notizfenster erscheint</li><li>Titel und Inhalt sind bereits ausgefüllt</li><li>Tags wurden automatisch generiert (beginnend mit <code>#</code>)</li></ul><h3 id="schritt-4-gespeicherte-notiz-uberprufen" tabindex="-1">Schritt 4: Gespeicherte Notiz überprüfen <a class="header-anchor" href="#schritt-4-gespeicherte-notiz-uberprufen" aria-label="Permalink to &quot;Schritt 4: Gespeicherte Notiz überprüfen&quot;">​</a></h3><p>Überprüfen Sie in Bear die neu erstellte Notiz und bestätigen Sie:</p><ul><li>Ist der Titel korrekt (aus der H1 des Plans)?</li><li>Ist der Inhalt vollständig (enthält den gesamten Plan)?</li><li>Sind die Tags sinnvoll (Projektname, Schlüsselwörter, Programmiersprachen)?</li></ul><p><strong>Erwartetes Ergebnis</strong>: Eine Notizstruktur ähnlich wie diese:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## User Authentication</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[Vollständiger Planinhalt...]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">#plannotator #myproject #authentication #typescript #api</span></span></code></pre></div><h2 id="checkliste-✅" tabindex="-1">Checkliste ✅ <a class="header-anchor" href="#checkliste-✅" aria-label="Permalink to &quot;Checkliste ✅&quot;">​</a></h2><ul><li>[ ] Bear Notes-Schalter in den Einstellungen ist aktiviert</li><li>[ ] Bear öffnet sich automatisch nach der Plangenehmigung</li><li>[ ] Notiztitel stimmt mit der H1 des Plans überein</li><li>[ ] Notiz enthält den vollständigen Planinhalt</li><li>[ ] Tags enthalten <code>#plannotator</code> und den Projektnamen</li></ul><h2 id="fehlerbehebung" tabindex="-1">Fehlerbehebung <a class="header-anchor" href="#fehlerbehebung" aria-label="Permalink to &quot;Fehlerbehebung&quot;">​</a></h2><h3 id="bear-offnet-sich-nicht-automatisch" tabindex="-1">Bear öffnet sich nicht automatisch <a class="header-anchor" href="#bear-offnet-sich-nicht-automatisch" aria-label="Permalink to &quot;Bear öffnet sich nicht automatisch&quot;">​</a></h3><p><strong>Ursache</strong>: Der System-<code>open</code>-Befehl ist fehlgeschlagen, möglicherweise weil:</p><ul><li>Bear ist nicht installiert oder wurde nicht aus dem App Store heruntergeladen</li><li>Das URL-Schema von Bear wird von einer anderen App überschrieben</li></ul><p><strong>Lösung</strong>:</p><ol><li>Bestätigen Sie, dass Bear ordnungsgemäß installiert ist</li><li>Testen Sie manuell im Terminal: <code>open &quot;bear://x-callback-url/create?title=test&quot;</code></li></ol><h3 id="tags-entsprechen-nicht-den-erwartungen" tabindex="-1">Tags entsprechen nicht den Erwartungen <a class="header-anchor" href="#tags-entsprechen-nicht-den-erwartungen" aria-label="Permalink to &quot;Tags entsprechen nicht den Erwartungen&quot;">​</a></h3><p><strong>Ursache</strong>: Tags werden automatisch nach folgenden Regeln generiert:</p><ul><li>Pflicht: <code>#plannotator</code></li><li>Pflicht: Projektname (aus Git-Repository-Name oder Verzeichnisname extrahiert)</li><li>Optional: Bis zu 3 Schlüsselwörter aus dem H1-Titel (Stoppwörter ausgeschlossen)</li><li>Optional: Programmiersprachen-Tags aus Codeblöcken (json/yaml/markdown ausgeschlossen)</li><li>Maximal 7 Tags</li></ul><p><strong>Lösung</strong>:</p><ul><li>Wenn Tags nicht den Erwartungen entsprechen, können Sie sie manuell in Bear bearbeiten</li><li>Wenn der Projektname falsch ist, überprüfen Sie die Git-Repository-Konfiguration oder den Verzeichnisnamen</li></ul><h3 id="genehmigt-aber-nicht-gespeichert" tabindex="-1">Genehmigt, aber nicht gespeichert <a class="header-anchor" href="#genehmigt-aber-nicht-gespeichert" aria-label="Permalink to &quot;Genehmigt, aber nicht gespeichert&quot;">​</a></h3><p><strong>Ursache</strong>:</p><ul><li>Bear-Schalter ist nicht aktiviert (überprüfen Sie die Einstellungen)</li><li>Netzwerkfehler oder Bear-Timeout</li><li>Planinhalt ist leer</li></ul><p><strong>Lösung</strong>:</p><ol><li>Bestätigen Sie, dass der Schalter in den Einstellungen blau ist (aktiviert)</li><li>Überprüfen Sie das Terminal auf Fehlerprotokolle (<code>[Bear] Save failed:</code>)</li><li>Genehmigen Sie den Plan erneut</li></ol><h2 id="tag-generierungsmechanismus-im-detail" tabindex="-1">Tag-Generierungsmechanismus im Detail <a class="header-anchor" href="#tag-generierungsmechanismus-im-detail" aria-label="Permalink to &quot;Tag-Generierungsmechanismus im Detail&quot;">​</a></h2><p>Plannotator generiert intelligente Tags, damit Sie Pläne in Bear schnell finden können. Hier sind die Generierungsregeln:</p><table tabindex="0"><thead><tr><th>Tag-Quelle</th><th>Beispiel</th><th>Priorität</th></tr></thead><tbody><tr><td>Festes Tag</td><td><code>#plannotator</code></td><td>Pflicht</td></tr><tr><td>Projektname</td><td><code>#myproject</code>, <code>#plannotator</code></td><td>Pflicht</td></tr><tr><td>H1-Schlüsselwörter</td><td><code>#authentication</code>, <code>#api</code></td><td>Optional (max. 3)</td></tr><tr><td>Programmiersprache</td><td><code>#typescript</code>, <code>#python</code></td><td>Optional</td></tr></tbody></table><p><strong>Stoppwortliste</strong> (werden nicht als Tags verwendet):</p><ul><li><code>the</code>, <code>and</code>, <code>for</code>, <code>with</code>, <code>this</code>, <code>that</code>, <code>from</code>, <code>into</code></li><li><code>plan</code>, <code>implementation</code>, <code>overview</code>, <code>phase</code>, <code>step</code>, <code>steps</code></li></ul><p><strong>Ausgeschlossene Programmiersprachen</strong> (werden nicht als Tags verwendet):</p><ul><li><code>json</code>, <code>yaml</code>, <code>yml</code>, <code>text</code>, <code>txt</code>, <code>markdown</code>, <code>md</code></li></ul><details class="details custom-block"><summary>Beispiel: Tag-Generierungsprozess</summary><p>Angenommen, der Plantitel lautet „Implementation Plan: User Authentication System in TypeScript&quot; und die Codeblöcke enthalten Python und JSON:</p><ol><li><strong>Festes Tag</strong>: <code>#plannotator</code></li><li><strong>Projektname</strong>: <code>#myproject</code> (angenommener Git-Repository-Name)</li><li><strong>H1-Schlüsselwörter</strong>: <ul><li><code>implementation</code> → ausgeschlossen (Stoppwort)</li><li><code>plan</code> → ausgeschlossen (Stoppwort)</li><li><code>user</code> → beibehalten → <code>#user</code></li><li><code>authentication</code> → beibehalten → <code>#authentication</code></li><li><code>system</code> → beibehalten → <code>#system</code></li><li><code>typescript</code> → beibehalten → <code>#typescript</code></li></ul></li><li><strong>Programmiersprachen</strong>: <ul><li><code>python</code> → beibehalten → <code>#python</code></li><li><code>json</code> → ausgeschlossen (Ausschlussliste)</li></ul></li></ol><p>Endgültige Tags: <code>#plannotator #myproject #user #authentication #system #typescript #python</code> (7, Maximum erreicht)</p></details><h2 id="vergleich-mit-obsidian-integration" tabindex="-1">Vergleich mit Obsidian-Integration <a class="header-anchor" href="#vergleich-mit-obsidian-integration" aria-label="Permalink to &quot;Vergleich mit Obsidian-Integration&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Merkmal</th><th>Bear-Integration</th><th>Obsidian-Integration</th></tr></thead><tbody><tr><td>Konfigurationskomplexität</td><td>Einfach (nur Schalter)</td><td>Mittel (Vault und Ordner auswählen)</td></tr><tr><td>Speicherort</td><td>Innerhalb der Bear-App</td><td>Angegebener Vault-Pfad</td></tr><tr><td>Dateiname</td><td>Von Bear automatisch verwaltet</td><td><code>Title - Mon D, YYYY H-MMam.md</code></td></tr><tr><td>Frontmatter</td><td>Nein (Bear unterstützt es nicht)</td><td>Ja (created, source, tags)</td></tr><tr><td>Plattformübergreifend</td><td>Nur macOS</td><td>macOS/Windows/Linux</td></tr><tr><td>x-callback-url</td><td>✅ Verwendet</td><td>❌ Schreibt direkt in Datei</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Welche sollten Sie wählen?</p><ul><li>Wenn Sie nur macOS verwenden und Bear mögen: Bear-Integration ist einfacher</li><li>Wenn Sie plattformübergreifende Unterstützung oder benutzerdefinierte Speicherpfade benötigen: Obsidian-Integration ist flexibler</li><li>Wenn Sie beide nutzen möchten: Sie können beide gleichzeitig aktivieren (genehmigte Pläne werden an beiden Orten gespeichert)</li></ul></div><h2 id="zusammenfassung" tabindex="-1">Zusammenfassung <a class="header-anchor" href="#zusammenfassung" aria-label="Permalink to &quot;Zusammenfassung&quot;">​</a></h2><ul><li>Die Bear-Integration funktioniert über das x-callback-url-Protokoll und ist einfach zu konfigurieren</li><li>Aktivieren Sie einfach den Schalter in den Einstellungen, ohne einen Pfad anzugeben</li><li>Pläne werden bei der Genehmigung automatisch in Bear gespeichert</li><li>Tags werden intelligent generiert, einschließlich Projektname, Schlüsselwörter und Programmiersprachen (maximal 7)</li><li>Im Vergleich zur Obsidian-Integration ist Bear einfacher, aber weniger funktionsreich</li></ul><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen Sie den <strong><a href="./../remote-mode/">Remote-/Devcontainer-Modus</a></strong>.</p><p>Sie werden lernen:</p><ul><li>Wie Sie Plannotator in Remote-Umgebungen (SSH, Devcontainer, WSL) verwenden</li><li>Konfiguration von festen Ports und Port-Weiterleitung</li><li>Öffnen des Browsers in Remote-Umgebungen zur Anzeige der Review-Seite</li></ul></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken Sie hier, um die Quellcode-Positionen anzuzeigen</strong></summary><blockquote><p>Aktualisiert: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilen</th></tr></thead><tbody><tr><td>Bear-Konfigurationsschnittstelle</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L18-L20" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>18-20</td></tr><tr><td>In Bear speichern</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L234-L257" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>234-257</td></tr><tr><td>Tag-Extraktion</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L34-L74" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>34-74</td></tr><tr><td>Titel-Extraktion</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L94-L105" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>94-105</td></tr><tr><td>Bear-Einstellungsschnittstelle</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/bear.ts#L15-L17" target="_blank" rel="noreferrer"><code>packages/ui/utils/bear.ts</code></a></td><td>15-17</td></tr><tr><td>Bear-Einstellungen lesen</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/bear.ts#L22-L26" target="_blank" rel="noreferrer"><code>packages/ui/utils/bear.ts</code></a></td><td>22-26</td></tr><tr><td>Bear-Einstellungen speichern</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/bear.ts#L31-L33" target="_blank" rel="noreferrer"><code>packages/ui/utils/bear.ts</code></a></td><td>31-33</td></tr><tr><td>UI-Einstellungskomponente</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/Settings.tsx#L496-L518" target="_blank" rel="noreferrer"><code>packages/ui/components/Settings.tsx</code></a></td><td>496-518</td></tr><tr><td>Bear bei Genehmigung aufrufen</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/editor/App.tsx#L512-L514" target="_blank" rel="noreferrer"><code>packages/editor/App.tsx</code></a></td><td>512-514</td></tr><tr><td>Server-Bear-Verarbeitung</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L250-L257" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>250-257</td></tr></tbody></table><p><strong>Wichtige Funktionen</strong>:</p><ul><li><code>saveToBear(config: BearConfig)</code>: Speichert den Plan über x-callback-url in Bear</li><li><code>extractTags(markdown: string)</code>: Extrahiert intelligent Tags aus dem Planinhalt (maximal 7)</li><li><code>extractTitle(markdown: string)</code>: Extrahiert den Notiztitel aus der H1-Überschrift des Plans</li><li><code>getBearSettings()</code>: Liest Bear-Integrationseinstellungen aus localStorage</li><li><code>saveBearSettings(settings)</code>: Speichert Bear-Integrationseinstellungen in localStorage</li></ul><p><strong>Wichtige Konstanten</strong>:</p><ul><li><code>STORAGE_KEY_ENABLED = &#39;plannotator-bear-enabled&#39;</code>: Schlüsselname für Bear-Einstellungen in localStorage</li></ul><p><strong>Bear-URL-Format</strong>:</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bear</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//x-callback-url/create?title={title}&amp;text={content}&amp;open_note=no</span></span></code></pre></div></details>`,75)])])}const p=t(r,[["render",l]]);export{u as __pageData,p as default};
